.sig-brutalist-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid #111111;
  border-radius: 0px;
  background: linear-gradient(145deg, #f8f1cf, #111111);
  color: #111111;
  box-shadow: 10px 10px 0 rgba(0,0,0,0.94);
  font-family: Arial, Helvetica, sans-serif;
}
.sig-brutalist-hero::before { content: ""; position: absolute; inset: 0; background: linear-gradient(90deg, rgba(17,17,17,0.12) 1px, transparent 1px), linear-gradient(0deg, rgba(17,17,17,0.12) 1px, transparent 1px); background-size: 24px 24px; opacity: 0.78; pointer-events: none; }
.sig-brutalist-hero > * { position: relative; z-index: 1; }
.sig-brutalist-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-brutalist-hero .kicker { width: fit-content; border: 1px solid #111111; border-radius: 999px; padding: 6px 10px; color: #e03b2f; background: #111111; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-brutalist-hero h1 { margin: 0; max-width: 620px; font-family: Arial Black, Arial, Helvetica, sans-serif; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-brutalist-hero p { margin: 0; max-width: 560px; color: #4c4636; font-size: 15px; line-height: 1.78; }
.sig-brutalist-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-brutalist-hero button { height: 40px; padding: 0 16px; border-radius: calc(0px / 2 + 4px); border: 1px solid #111111; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-brutalist-hero .primary { background: #e03b2f; color: #fff7d6; border-color: #e03b2f; }
.sig-brutalist-hero .secondary { background: transparent; color: #111111; }
.sig-brutalist-hero button:hover { transform: translateY(-1px); border-color: #e03b2f; }
.sig-brutalist-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid #111111; border-radius: calc(0px - 2px); background: #111111; backdrop-filter: blur(18px) saturate(140%); }
.sig-brutalist-hero .artifact h2 { margin: 0; font-size: 13px; color: #e03b2f; text-transform: uppercase; letter-spacing: 0; }
.sig-brutalist-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-brutalist-hero .metric { padding: 14px; border: 1px solid #111111; border-radius: calc(0px - 4px); background: color-mix(in srgb, #f8f1cf 76%, transparent); }
.sig-brutalist-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-brutalist-hero .metric span { display: block; margin-top: 6px; color: #4c4636; font-size: 11px; }
.sig-brutalist-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #e03b2f, #111111); }
@media (max-width: 780px) { .sig-brutalist-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-brutalist-card { width: min(100%, 390px); padding: 22px; border: 1px solid #111111; border-radius: 0px; background: #f8f1cf; color: #111111; box-shadow: 10px 10px 0 rgba(0,0,0,0.94); font-family: Arial, Helvetica, sans-serif; }
.sig-brutalist-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-brutalist-card .label { color: #e03b2f; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-brutalist-card .pill { border: 1px solid #111111; border-radius: 999px; padding: 5px 9px; color: #4c4636; background: #111111; font-size: 11px; }
.sig-brutalist-card h3 { margin: 0 0 10px; font-family: Arial Black, Arial, Helvetica, sans-serif; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-brutalist-card p { margin: 0; color: #4c4636; font-size: 13px; line-height: 1.7; }
.sig-brutalist-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid #111111; }
.sig-brutalist-card .strip strong { font-variant-numeric: tabular-nums; color: #111111; }
.sig-brutalist-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(0px - 4px); background: #e03b2f; color: #fff7d6; font-weight: 900; }

.sig-brutalist-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid #111111; border-radius: 0px; background: #f8f1cf; color: #111111; box-shadow: 10px 10px 0 rgba(0,0,0,0.94); font-family: Arial, Helvetica, sans-serif; }
.sig-brutalist-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: Arial Black, Arial, Helvetica, sans-serif; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-brutalist-nav .mark { width: 30px; height: 30px; border-radius: calc(0px - 4px); background: linear-gradient(135deg, #e03b2f, #111111); box-shadow: inset 0 0 0 1px #111111; }
.sig-brutalist-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-brutalist-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(0px - 6px); color: #4c4636; text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-brutalist-nav a:hover, .sig-brutalist-nav a.active { color: #111111; background: #111111; }
.sig-brutalist-nav button { height: 34px; padding: 0 13px; border-radius: calc(0px - 6px); border: 1px solid #e03b2f; background: #e03b2f; color: #fff7d6; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-brutalist-nav { align-items: stretch; flex-direction: column; } }

.sig-brutalist-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid #111111; border-radius: 0px; background: #f8f1cf; color: #111111; box-shadow: 10px 10px 0 rgba(0,0,0,0.94); font-family: Arial, Helvetica, sans-serif; }
.sig-brutalist-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #111111; }
.sig-brutalist-form small { color: #4c4636; font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-brutalist-form .row { display: flex; gap: 10px; }
.sig-brutalist-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(0px - 6px); border: 1px solid #111111; background: #111111; color: #111111; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-brutalist-form input:focus { border-color: #e03b2f; box-shadow: 0 0 0 3px color-mix(in srgb, #e03b2f 18%, transparent); }
.sig-brutalist-form button { height: 42px; padding: 0 14px; border-radius: calc(0px - 6px); border: 1px solid #e03b2f; background: #e03b2f; color: #fff7d6; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-brutalist-form .row { flex-direction: column; } }

.sig-brutalist-table { width: min(100%, 780px); overflow: hidden; border: 1px solid #111111; border-radius: 0px; background: #f8f1cf; color: #111111; box-shadow: 10px 10px 0 rgba(0,0,0,0.94); font-family: Arial, Helvetica, sans-serif; }
.sig-brutalist-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-brutalist-table th, .sig-brutalist-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid #111111; }
.sig-brutalist-table th { color: #4c4636; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: #111111; }
.sig-brutalist-table td { color: #111111; }
.sig-brutalist-table tr:last-child td { border-bottom: 0; }
.sig-brutalist-table tbody tr:hover td { background: #111111; }
.sig-brutalist-table .mono { font-variant-numeric: tabular-nums; }
.sig-brutalist-table .status { display: inline-flex; align-items: center; gap: 6px; color: #e03b2f; font-weight: 800; }
.sig-brutalist-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #e03b2f; }

.btn-raw {
  padding: 14px 32px;
  background: #000;
  color: #fff;
  font-family: 'Courier New', monospace;
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  border: none;
  border-radius: 0;
  cursor: pointer;
  box-shadow: 4px 4px 0 #000;
  position: relative;
  transition: transform 0.1s, box-shadow 0.1s;
}
.btn-raw::before {
  content: '';
  position: absolute;
  inset: -4px;
  border: 2px solid #000;
}
.btn-raw:hover {
  transform: translate(2px, 2px);
  box-shadow: 2px 2px 0 #000;
}
.btn-raw:active {
  transform: translate(4px, 4px);
  box-shadow: 0 0 0 #000;
}

.footer-brutalist {
  background: #000;
  color: #fff;
  border-top: 4px solid #fff;
  padding: 32px 24px;
  font-family: 'Courier New', monospace;
  font-size: 12px;
  line-height: 2;
}
.footer-brutalist a { color: #fff; }
.footer-brutalist .divider { margin: 16px 0; border: none; border-top: 1px solid #333; }

.btn-stamp {
  padding: 12px 28px;
  background: transparent;
  color: #dc2626;
  font-family: 'Space Mono', monospace;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  border: 3px dashed #dc2626;
  border-radius: 0;
  cursor: pointer;
  transform: rotate(-2deg);
  transition: all 0.2s;
}
.btn-stamp:hover {
  transform: rotate(0deg);
  background: #dc2626;
  color: #fff;
  border-style: solid;
}
.btn-stamp:active {
  transform: rotate(0deg) scale(0.95);
}
